  const items = [
    NavItem({ text: 'Home', active: true }),
    NavItem({ text: 'About', active: false }),
    NavItem({ text: 'Contact', active: false })
  ];
  return { type: 'nav', props: { children: items } };
}

const nav = Navbar();
nav.props.children.forEach(item => {
