exercises.solution:
const glossary = [
  { id: 'jsx', term: 'JSX', definition: 'A syntax extension for JavaScript' },
  { id: 'comp', term: 'Component', definition: 'A reusable piece of UI' },
  { id: 'prop', term: 'Props', definition: 'Data passed to components' }
];

function renderGlossary(items) {
  return items.map(item => ({
    key: item.id,
    type: 'Fragment',
    props: {
      children: [
        { type: 'dt', props: { children: item.term } },
        { type: 'dd', props: { children: item.definition } }
      ]
    }
  }));
}

const result = renderGlossary(glossary);
result.forEach(fragment => {
  const [dt, dd] = fragment.props.children;
  console.log(fragment.key + ': ' + dt.props.children + ' = ' + dd.props.children);
});

