exercises.solution:
function buildButtonProps(config) {
  const baseProps = {
    type: 'button',
    className: 'btn'
  };

  const variantProps = config.variant ? { className: 'btn btn-' + config.variant } : {};
  const disabledProps = config.disabled ? { disabled: true } : {};
  const labelProps = config.label ? { 'aria-label': config.label } : {};

  return { ...baseProps, ...variantProps, ...disabledProps, ...labelProps };
}

const primary = buildButtonProps({ variant: 'primary', disabled: false, label: 'Save' });
console.log(primary.className);
console.log(primary.disabled);
console.log(primary['aria-label']);

const disabledBtn = buildButtonProps({ disabled: true });
console.log(disabledBtn.className);
console.log(disabledBtn.disabled);
